import{G as a,c as i,b as e,ae as n}from"./chunks/framework.Cpb2nuHT.js";const t="/assets/2025-09-17-9DoBVo.D6R-GHgH.png",l="/assets/2025-09-17-FbYWYk.DEjieOyH.png",g=JSON.parse('{"title":"索引","description":"","frontmatter":{"title":"索引","date":"2024-08-13T15:56:25.000Z","author":"花木凋零成兰","tags":["索引"],"cover":false,"hiddenCover":true},"headers":[],"relativePath":"Database/MySQL/索引.md","filePath":"Database/MySQL/索引.md","lastUpdated":1758072482000}'),p={name:"Database/MySQL/索引.md"};function r(h,s,E,o,d,k){return e(),i("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1723564585000"},[...s[0]||(s[0]=[n(`<h1 id="索引" tabindex="-1">索引 <a class="header-anchor" href="#索引" aria-label="Permalink to &quot;索引&quot;">​</a></h1><h2 id="索引数据结构" tabindex="-1">索引数据结构 <a class="header-anchor" href="#索引数据结构" aria-label="Permalink to &quot;索引数据结构&quot;">​</a></h2><p><strong>重点问题：</strong></p><blockquote><p>什么是索引?为什么索引能加快查询?</p><p>索引的数据结构是什么?</p><p>B+树和(B树和红黑树)有什么区别?为什么选择用B+树作为索引数据结构?</p></blockquote><h3 id="索引-1" tabindex="-1">索引 <a class="header-anchor" href="#索引-1" aria-label="Permalink to &quot;索引&quot;">​</a></h3><p><strong>索引是提升查询速度的一种数据结构</strong>; 之所以能提升查询速度, 是因为它在插入数据时对数据进行了排序; 所以会存在一个明显的缺点：影响插入或更新的性能;</p><p>总之, 有效地设计并创建索引, 可以提升数据库系统的整体性能; 在目前的 MySQL 8.0 版本中, InnoDB 存储引擎支持的索引有 B+ 树索引、全文索引、R 树索引;</p><p>一个适合 MySQL 索引的数据结构应该满足以下要求：</p><ol><li>能在尽可能少的磁盘 I/O 操作中完成查询工作;</li><li>要能高效地查询某一个记录, 也要能高效地执行范围查找</li></ol><h3 id="b-树索引结构" tabindex="-1">B+ 树索引结构 <a class="header-anchor" href="#b-树索引结构" aria-label="Permalink to &quot;B+ 树索引结构&quot;">​</a></h3><blockquote><p>若对 B+ 树存在疑问, 可查看该文章：<a href="https://xiaolincoding.com/mysql/index/why_index_chose_bpuls_tree.html#%E6%80%8E%E6%A0%B7%E7%9A%84%E7%B4%A2%E5%BC%95%E7%9A%84%E6%95%B0%E6%8D%AE%E7%BB%93%E6%9E%84%E6%98%AF%E5%A5%BD%E7%9A%84" target="_blank" rel="noreferrer">为什么 MySQL 采用 B+ 树作为索引？</a>进行了解;</p></blockquote><p>B+ 树索引是数据库系统中最为常见的一种索引数据结构, 几乎所有关系型数据库都支持它, <strong>是目前为止排序最有效率的数据结构</strong>, 像二叉树,哈希索引,红黑树,SkipList, 在海量数据基于磁盘存储效率方面都不如 B+ 树索引高效;</p><blockquote><p>上述的数据结构一般仅用于内存对象，基于磁盘的数据排序与存储，最有效的依然是 B+ 树索引;</p></blockquote><p><strong>B+ 树索引特点：</strong> 基于磁盘的平衡树, 树非常矮, 只需要 3~4 层, 能存放千万到上亿的排序数据; 树矮则访问效率高, 只需要 3~4 次IO, 就能查到一条数据;</p><p>B+ 树索引由根节点、中间节点、叶子节点组成, 其中只有叶子节点存放排序后的数据, 当高度为1时, 根节点也是叶子节点, 即此时会在根节点存放数据;</p><p>对于 B+ 树中每个节点的数据结构可以看：<a href="https://xiaolincoding.com/mysql/index/page.html#innodb-%E6%98%AF%E5%A6%82%E4%BD%95%E5%AD%98%E5%82%A8%E6%95%B0%E6%8D%AE%E7%9A%84" target="_blank" rel="noreferrer">从数据页的角度看 B+ 树</a></p><h3 id="b-树索引插入性能" tabindex="-1">B+ 树索引插入性能 <a class="header-anchor" href="#b-树索引插入性能" aria-label="Permalink to &quot;B+ 树索引插入性能&quot;">​</a></h3><p>虽然 B+ 树在插入时要对数据进行排序, 但是排序的开销并不大, 因为是由 CPU 来负责操作;</p><p><strong>真正的开销是 B+ 树索引的维护, 保证数据排序, 存在两种不同数据类型的插入情况</strong>：</p><ul><li><strong>数据顺序(逆序)插入</strong>：B+ 树索引的维护代价非常小, 叶子节点都是从左往右进行插入, 比较典型是自增 ID 的插入、时间的插入(若在自增 ID 或 时间列 上创建索引, 插入通常是比较快的);</li><li><strong>数据无序插入</strong>：B+ 树为了维护排序, 需要对页进行分裂、旋转等开销较大的操作, 另外, 对于硬盘的随机写性能也不如顺序写, 所以磁盘性能也会受到较大影响, 比较典型的是用户昵称, 因为每个用户注册时, 昵称是随意取的, 若在昵称上创建索引, 插入是无序的, 索引维护需要的开销会比较大;</li></ul><p>所以对于 B+ 树索引, 主要要求<strong>主键的索引设计尽可能为顺序值</strong>, 比如使用自增, 或使用UUID_TO_BIN 排序的 UUID, 而不用无序值做主键;</p><h3 id="b-树索引的设计管理" tabindex="-1">B+ 树索引的设计管理 <a class="header-anchor" href="#b-树索引的设计管理" aria-label="Permalink to &quot;B+ 树索引的设计管理&quot;">​</a></h3><p>在 MySQL 数据库中, 可以通过查询表 mysql.innodb_index_stats 查看每个索引情况, 执行如下命令：</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    table_name,index_name,stat_name,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    stat_value,stat_description</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> innodb_index_stats</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> table_name </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;discuss_post&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> and</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> index_name </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;PRIMARY&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>查询结果如下所示：</p><p><img src="`+t+`" alt="" loading="lazy"></p><p>从上图可以看出, 表 discuss_post 中的主键索引, 大约有 324912 条数据, 叶子节点一共 20309 个页, 索引所有页的数量为 20340; 所以可以得到非叶子节点为 20340-20309 = 31 个; 即非叶子节点有 31 页;</p><p>此外, 对于一张表中的索引数量, 应该<strong>根据具体的业务来创建对应的索引</strong>; 避免创建无用索引;</p><p>对于 B+ 树索引的使用情况, 可以在 MySQL 数据库中, 查询表 sys.schema_unused_indexes 来获取哪些索引一直未被使用过, 可以被废弃, 执行命令如下：</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> schema_unused_indexes</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> object_schema </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">!=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;performance_schema&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>查询结果如下：</p><p><img src="`+l+`" alt="" loading="lazy"></p><p><code>object_schema</code> 指数据库名, <code>object_name</code> 指表名, <code>index_name</code>指索引名;</p><p>当数据库运行时间较长, 索引创建时间较久, 索引还从未使用过, 则可以考虑删除没用的索引;</p><p>此外, 在 MySQL 8.0 中有索引不可见的功能, 在删除索引之前, 可以通过如下命令, 将索引设置为对优化器不可见, 然后观察对业务是否有影响, 若没有影响, 则可以放心的删除无用索引;</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ALTER</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> TABLE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 表名</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ALTER</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> INDEX</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 索引名 INVISIBLE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">VISIBLE;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h3><ul><li><a href="https://security.feishu.cn/link/safety?target=https%3A%2F%2Flearn.lianglianglee.com%2F%25E4%25B8%2593%25E6%25A0%258F%2FMySQL%25E5%25AE%259E%25E6%2588%2598%25E5%25AE%259D%25E5%2585%25B8%2F08%2520%2520%25E7%25B4%25A2%25E5%25BC%2595%25EF%25BC%259A%25E6%258E%2592%25E5%25BA%258F%25E7%259A%2584%25E8%2589%25BA%25E6%259C%25AF.md&amp;scene=ccm&amp;logParams=%7B%22location%22%3A%22ccm_docs%22%7D&amp;lang=zh-CN" target="_blank" rel="noreferrer">08 索引：排序的艺术</a></li><li><a href="https://xiaolincoding.com/mysql/index/why_index_chose_bpuls_tree.html#%E6%80%8E%E6%A0%B7%E7%9A%84%E7%B4%A2%E5%BC%95%E7%9A%84%E6%95%B0%E6%8D%AE%E7%BB%93%E6%9E%84%E6%98%AF%E5%A5%BD%E7%9A%84" target="_blank" rel="noreferrer">为什么 MySQL 采用 B+ 树作为索引？</a></li><li><a href="http://121.43.36.222:5244/%E8%B5%84%E6%BA%90/14-%E6%9E%81%E5%AE%A2%E6%97%B6%E9%97%B4/%E4%B8%93%E6%A0%8F%E8%AF%BE/2024/230%E5%90%8E%E7%AB%AF%E5%B7%A5%E7%A8%8B%E5%B8%88%E7%9A%84%E9%AB%98%E9%98%B6%E9%9D%A2%E7%BB%8F/10%EF%BD%9C%E6%95%B0%E6%8D%AE%E5%BA%93%E7%B4%A2%E5%BC%95%EF%BC%9A%E4%B8%BA%E4%BB%80%E4%B9%88MySQL%E7%94%A8B+%E6%A0%91%E8%80%8C%E4%B8%8D%E7%94%A8B%E6%A0%91%EF%BC%9F.md" target="_blank" rel="noreferrer">数据库索引：为什么MySQL用B+树而不用B树？</a></li></ul>`,38)])])}const B=a(p,[["render",r]]);export{g as __pageData,B as default};
